import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';
import { Carrier, VEHICLE_TYPES, VEHICLE_CAPACITIES, LOAD_TYPES, LoadType } from '@/lib/types';
import { saveCarrier, setCurrentUser } from '@/lib/storage';
import { generateId } from '@/lib/utils';
import { toast } from 'sonner';

interface CarrierRegistrationProps {
  onSuccess: () => void;
}

export default function CarrierRegistration({ onSuccess }: CarrierRegistrationProps) {
  const [formData, setFormData] = useState({
    name: '',
    surname: '',
    email: '',
    phone: '',
    city: '',
    vehicleType: '',
    licensePlate: '',
    serviceAreas: '',
    baseFee: '100',
  });

  const [selectedLoadTypes, setSelectedLoadTypes] = useState<LoadType[]>([]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name || !formData.surname || !formData.email || !formData.phone || !formData.vehicleType || !formData.licensePlate) {
      toast.error('Lütfen tüm zorunlu alanları doldurun');
      return;
    }

    if (selectedLoadTypes.length === 0) {
      toast.error('Lütfen en az bir yük türü seçin');
      return;
    }

    const vehicleType = formData.vehicleType as keyof typeof VEHICLE_CAPACITIES;
    const capacity = VEHICLE_CAPACITIES[vehicleType];

    const carrier: Carrier = {
      id: generateId(),
      name: formData.name,
      surname: formData.surname,
      email: formData.email,
      phone: formData.phone,
      city: formData.city,
      type: 'carrier',
      vehicle: {
        type: vehicleType,
        capacity,
        licensePlate: formData.licensePlate,
      },
      serviceAreas: formData.serviceAreas.split(',').map(area => area.trim()).filter(Boolean),
      loadTypes: selectedLoadTypes,
      documents: {
        license: '',
        src: '',
        kBelgesi: '',
      },
      rating: 5.0,
      reviewCount: 0,
      isApproved: false, // Admin approval required
      baseFee: parseInt(formData.baseFee),
      createdAt: new Date(),
    };

    saveCarrier(carrier);
    setCurrentUser(carrier);
    toast.success('Nakliyeci kaydınız alındı! Admin onayı bekleniyor.');
    onSuccess();
  };

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleLoadTypeChange = (loadType: LoadType, checked: boolean) => {
    if (checked) {
      setSelectedLoadTypes(prev => [...prev, loadType]);
    } else {
      setSelectedLoadTypes(prev => prev.filter(type => type !== loadType));
    }
  };

  return (
    <Card className="w-full max-w-2xl mx-auto">
      <CardHeader>
        <CardTitle className="text-center">Nakliyeci Kaydı</CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="name">Ad *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => handleChange('name', e.target.value)}
                placeholder="Adınızı girin"
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="surname">Soyad *</Label>
              <Input
                id="surname"
                value={formData.surname}
                onChange={(e) => handleChange('surname', e.target.value)}
                placeholder="Soyadınızı girin"
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="email">E-posta *</Label>
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => handleChange('email', e.target.value)}
                placeholder="E-posta adresinizi girin"
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="phone">Telefon *</Label>
              <Input
                id="phone"
                value={formData.phone}
                onChange={(e) => handleChange('phone', e.target.value)}
                placeholder="Telefon numaranızı girin"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="city">Şehir</Label>
            <Input
              id="city"
              value={formData.city}
              onChange={(e) => handleChange('city', e.target.value)}
              placeholder="Şehrinizi girin"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="vehicleType">Araç Tipi *</Label>
              <Select onValueChange={(value) => handleChange('vehicleType', value)}>
                <SelectTrigger>
                  <SelectValue placeholder="Araç tipi seçin" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(VEHICLE_TYPES).map(([key, label]) => (
                    <SelectItem key={key} value={key}>
                      {label} (Max: {VEHICLE_CAPACITIES[key as keyof typeof VEHICLE_CAPACITIES]/1000} ton)
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="licensePlate">Plaka *</Label>
              <Input
                id="licensePlate"
                value={formData.licensePlate}
                onChange={(e) => handleChange('licensePlate', e.target.value)}
                placeholder="Araç plakasını girin"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="serviceAreas">Hizmet Verdiğiniz Bölgeler</Label>
            <Input
              id="serviceAreas"
              value={formData.serviceAreas}
              onChange={(e) => handleChange('serviceAreas', e.target.value)}
              placeholder="Şehirleri virgülle ayırın (örn: İstanbul, Ankara, İzmir)"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="baseFee">Taban Ücret (TL)</Label>
            <Input
              id="baseFee"
              type="number"
              value={formData.baseFee}
              onChange={(e) => handleChange('baseFee', e.target.value)}
              placeholder="Minimum taşıma ücreti"
            />
          </div>

          <div className="space-y-3">
            <Label>Taşıdığınız Yük Türleri *</Label>
            <div className="grid grid-cols-2 gap-3">
              {Object.entries(LOAD_TYPES).map(([key, label]) => (
                <div key={key} className="flex items-center space-x-2">
                  <Checkbox
                    id={key}
                    checked={selectedLoadTypes.includes(key as LoadType)}
                    onCheckedChange={(checked) => 
                      handleLoadTypeChange(key as LoadType, checked as boolean)
                    }
                  />
                  <Label htmlFor={key} className="text-sm font-normal">
                    {label}
                  </Label>
                </div>
              ))}
            </div>
          </div>

          <Button type="submit" className="w-full">
            Nakliyeci Kaydı Yap
          </Button>

          <p className="text-sm text-muted-foreground text-center">
            * Kayıt sonrası admin onayı beklemeniz gerekmektedir.
          </p>
        </form>
      </CardContent>
    </Card>
  );
}
</content>
