import { format } from 'date-fns';
import { tr } from 'date-fns/locale';
import { ShipmentRequest, LOAD_TYPES, LoadType, Location } from '@/lib/types';
import { saveShipment, getApprovedCarriers } from '@/lib/storage';
import { generateId, calculateDistance, calculatePrice, formatPrice } from '@/lib/utils';
import { toast } from 'sonner';

interface ShipmentRequestProps {
  customerId: string;
  onSuccess: () => void;
}

export default function ShipmentRequestComponent({ customerId, onSuccess }: ShipmentRequestProps) {
  const [formData, setFormData] = useState({
    originAddress: '',
    destinationAddress: '',
    loadType: '',
    weight: '',
    date: undefined as Date | undefined,
  });

  const [estimatedPrice, setEstimatedPrice] = useState<number | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.originAddress || !formData.destinationAddress || !formData.loadType || !formData.weight || !formData.date) {
      toast.error('Lütfen tüm alanları doldurun');
      return;
    }

    // Simplified location creation (in real app, would use geocoding)
    const origin: Location = {
      address: formData.originAddress,
      lat: 41.0082 + Math.random() * 0.1, // Istanbul area with some randomness
      lng: 28.9784 + Math.random() * 0.1,
    };

    const destination: Location = {
      address: formData.destinationAddress,
      lat: 39.9334 + Math.random() * 0.1, // Ankara area with some randomness
      lng: 32.8597 + Math.random() * 0.1,
    };

    const shipment: ShipmentRequest = {
      id: generateId(),
      customerId,
      origin,
      destination,
      loadType: formData.loadType as LoadType,
      weight: parseInt(formData.weight),
      date: formData.date,
      status: 'pending',
      createdAt: new Date(),
    };

    saveShipment(shipment);
    toast.success('Taşıma talebiniz oluşturuldu!');
    onSuccess();
  };

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Calculate estimated price when enough data is available
    if (field === 'weight' || (field === 'originAddress' && formData.destinationAddress) || (field === 'destinationAddress' && formData.originAddress)) {
      calculateEstimatedPrice();
    }
  };

  const calculateEstimatedPrice = () => {
    if (formData.originAddress && formData.destinationAddress && formData.weight) {
      // Simplified distance calculation (in real app, would use Google Maps API)
      const distance = Math.floor(Math.random() * 500) + 50; // Random distance between 50-550 km
      const weight = parseInt(formData.weight);

      if (weight > 0) {
        const carriers = getApprovedCarriers();
        if (carriers.length > 0) {
          // Use average base fee from carriers
          const avgBaseFee = carriers.reduce((sum, carrier) => sum + carrier.baseFee, 0) / carriers.length;
          const price = calculatePrice(distance, weight, 'kamyonet', avgBaseFee);
          setEstimatedPrice(price);
        }
      }
    }
  };

  return (
    <Card className="w-full max-w-2xl mx-auto">
      <CardHeader>
        <CardTitle className="text-center">Taşıma Talebi Oluştur</CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="originAddress">Yükleme Adresi *</Label>
            <Input
              id="originAddress"
              value={formData.originAddress}
              onChange={(e) => handleChange('originAddress', e.target.value)}
              placeholder="Yükün alınacağı adres"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="destinationAddress">Teslimat Adresi *</Label>
            <Input
              id="destinationAddress"
              value={formData.destinationAddress}
              onChange={(e) => handleChange('destinationAddress', e.target.value)}
              placeholder="Yükün teslim edileceği adres"
              required
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="loadType">Yük Türü *</Label>
              <Select onValueChange={(value) => handleChange('loadType', value)}>
                <SelectTrigger>
                  <SelectValue placeholder="Yük türü seçin" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(LOAD_TYPES).map(([key, label]) => (
                    <SelectItem key={key} value={key}>
                      {label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="weight">Ağırlık (kg) *</Label>
              <Input
                id="weight"
                type="number"
                value={formData.weight}
                onChange={(e) => handleChange('weight', e.target.value)}
                placeholder="Tahmini ağırlık"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>Taşıma Tarihi *</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  className="w-full justify-start text-left font-normal"
                >
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {formData.date ? format(formData.date, "PPP", { locale: tr }) : "Tarih seçin"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0">
                <Calendar
                  mode="single"
                  selected={formData.date}
                  onSelect={(date) => setFormData(prev => ({ ...prev, date }))}
                  disabled={(date) => date < new Date()}
                  initialFocus
                />
              </PopoverContent>
            </Popover>
          </div>

          {estimatedPrice && (
            <div className="p-4 bg-blue-50 rounded-lg">
              <p className="text-sm text-blue-600 font-medium">
                Tahmini Fiyat: {formatPrice(estimatedPrice)}
              </p>
              <p className="text-xs text-blue-500 mt-1">
                * Bu fiyat tahminidir. Nakliyecilerden gelen teklifler farklılık gösterebilir.
              </p>
            </div>
          )}

          <Button type="submit" className="w-full">
            Taşıma Talebi Oluştur
          </Button>
        </form>
      </CardContent>
    </Card>
  );
}
</content>
