import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Truck, Users, Star, MapPin, Package, Shield } from 'lucide-react';
import UserRegistration from '@/components/UserRegistration';
import CarrierRegistration from '@/components/CarrierRegistration';
import ShipmentRequest from '@/components/ShipmentRequest';
import CarrierProfile from '@/components/CarrierProfile';
import RatingSystem from '@/components/RatingSystem';
import { getCurrentUser, getApprovedCarriers, getShipments, getOffers } from '@/lib/storage';
import { User, Carrier, ShipmentRequest as ShipmentRequestType } from '@/lib/types';

export default function Index() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [carriers, setCarriers] = useState<Carrier[]>([]);
  const [userShipments, setUserShipments] = useState<ShipmentRequestType[]>([]);

  useEffect(() => {
    const user = getCurrentUser();
    setCurrentUser(user);

    if (user) {
      setActiveTab(user.type === 'customer' ? 'shipments' : 'profile');
    }

    // Load data
    setCarriers(getApprovedCarriers());

    if (user && user.type === 'customer') {
      const shipments = getShipments().filter(s => s.customerId === user.id);
      setUserShipments(shipments);
    }
  }, []);

  const handleRegistrationSuccess = () => {
    const user = getCurrentUser();
    setCurrentUser(user);
    if (user) {
      setActiveTab(user.type === 'customer' ? 'shipments' : 'profile');
    }
  };

  const handleShipmentSuccess = () => {
    if (currentUser && currentUser.type === 'customer') {
      const shipments = getShipments().filter(s => s.customerId === currentUser.id);
      setUserShipments(shipments);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('tasiburada_current_user');
    setCurrentUser(null);
    setActiveTab('home');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
        {/* Hero Section */}
        <div className="container mx-auto px-4 py-16">
          <div className="text-center mb-16">
            <h1 className="text-5xl font-bold text-gray-900 mb-6">
              🚚 Taşıburada
            </h1>
            <p className="text-xl text-gray-600 mb-8 max-w-3xl mx-auto">
              Nakliyeci ile müşteri arasındaki iletişimi dijitalleştiren, güvenli, hızlı ve şeffaf nakliye pazar yeri platformu
            </p>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">
              <div className="text-center">
                <div className="bg-blue-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Users className="h-8 w-8 text-blue-600" />
                </div>
                <h3 className="text-lg font-semibold mb-2">Kolay Eşleşme</h3>
                <p className="text-gray-600">Tek tıkla uygun nakliyeci bulun</p>
              </div>

              <div className="text-center">
                <div className="bg-green-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Shield className="h-8 w-8 text-green-600" />
                </div>
                <h3 className="text-lg font-semibold mb-2">Güvenli Taşıma</h3>
                <p className="text-gray-600">Sigorta ve güvenlik garantisi</p>
              </div>

              <div className="text-center">
                <div className="bg-purple-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Star className="h-8 w-8 text-purple-600" />
                </div>
                <h3 className="text-lg font-semibold mb-2">Puanlama Sistemi</h3>
                <p className="text-gray-600">Güvenilir nakliyecilerle çalışın</p>
              </div>
            </div>
          </div>

          {/* Registration Tabs */}
          <Tabs defaultValue="customer" className="max-w-4xl mx-auto">
            <TabsList className="grid w-full grid-cols-2 mb-8">
              <TabsTrigger value="customer">Müşteri Kaydı</TabsTrigger>
              <TabsTrigger value="carrier">Nakliyeci Kaydı</TabsTrigger>
            </TabsList>

            <TabsContent value="customer">
              <UserRegistration onSuccess={handleRegistrationSuccess} />
            </TabsContent>

            <TabsContent value="carrier">
              <CarrierRegistration onSuccess={handleRegistrationSuccess} />
            </TabsContent>
          </Tabs>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-bold text-blue-600">🚚 Taşıburada</h1>
            <div className="flex items-center gap-4">
              <span className="text-sm text-gray-600">
                Hoş geldin, {currentUser.name} {currentUser.surname}
              </span>
              <Button variant="outline" onClick={handleLogout}>
                Çıkış Yap
              </Button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="mb-8">
            {currentUser.type === 'customer' ? (
              <>
                <TabsTrigger value="shipments">Taşıma Talepleri</TabsTrigger>
                <TabsTrigger value="carriers">Nakliyeciler</TabsTrigger>
              </>
            ) : (
              <>
                <TabsTrigger value="profile">Profilim</TabsTrigger>
                <TabsTrigger value="jobs">İş Fırsatları</TabsTrigger>
              </>
            )}
          </TabsList>

          {currentUser.type === 'customer' && (
            <>
              <TabsContent value="shipments">
                <div className="space-y-6">
                  <ShipmentRequest 
                    customerId={currentUser.id} 
                    onSuccess={handleShipmentSuccess}
                  />

                  {userShipments.length > 0 && (
                    <div className="space-y-4">
                      <h3 className="text-lg font-semibold">Taşıma Talepleriniz</h3>
                      {userShipments.map((shipment) => (
                        <Card key={shipment.id}>
                          <CardContent className="p-4">
                            <div className="flex items-center justify-between">
                              <div>
                                <p className="font-medium">
                                  {shipment.origin.address} → {shipment.destination.address}
                                </p>
                                <p className="text-sm text-gray-600">
                                  {shipment.weight} kg • {new Date(shipment.date).toLocaleDateString('tr-TR')}
                                </p>
                              </div>
                              <div className="text-right">
                                <span className={`px-2 py-1 rounded text-xs font-medium ${
                                  shipment.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                                  shipment.status === 'matched' ? 'bg-blue-100 text-blue-800' :
                                  shipment.status === 'completed' ? 'bg-green-100 text-green-800' :
                                  'bg-red-100 text-red-800'
                                }`}>
                                  {shipment.status === 'pending' ? 'Bekliyor' :
                                   shipment.status === 'matched' ? 'Eşleşti' :
                                   shipment.status === 'completed' ? 'Tamamlandı' : 'İptal'}
                                </span>
                              </div>
                            </div>
                          </CardContent>
                        </Card>
                      ))}
                    </div>
                  )}
                </div>
              </TabsContent>

              <TabsContent value="carriers">
                <div className="space-y-6">
                  <h3 className="text-lg font-semibold">Onaylı Nakliyeciler</h3>
                  {carriers.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      {carriers.map((carrier) => (
                        <CarrierProfile key={carrier.id} carrier={carrier} />
                      ))}
                    </div>
                  ) : (
                    <Card>
                      <CardContent className="p-8 text-center">
                        <Truck className="h-12 w-12 text-gray-400 mx-auto mb-4" />
                        <p className="text-gray-600">Henüz onaylı nakliyeci bulunmuyor.</p>
                      </CardContent>
                    </Card>
                  )}
                </div>
              </TabsContent>
            </>
          )}

          {currentUser.type === 'carrier' && (
            <>
              <TabsContent value="profile">
                <CarrierProfile carrier={currentUser as Carrier} />
              </TabsContent>

              <TabsContent value="jobs">
                <Card>
                  <CardHeader>
                    <CardTitle>İş Fırsatları</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <p className="text-gray-600">
                      İş fırsatları yakında eklenecek. Admin onayınız tamamlandıktan sonra 
                      size uygun taşıma talepleri burada görünecek.
                    </p>
                  </CardContent>
                </Card>
              </TabsContent>
            </>
          )}
        </Tabs>
      </main>
    </div>
  );
}
</content>
